116	
117	  const passwordLastUsed = user.PasswordLastUsed
118	    ? new Date(user.PasswordLastUsed).toLocaleDateString()
119	    : DASH;
120	
121	  const path = `${IAM_BASE_ROUTE}/${userName}`;
122	
123	  const onSetFavorite = (key, active) => {
124	    setFavorites((oldFavorites) => [
125	      ...oldFavorites.filter((oldFavorite) => oldFavorite !== key),
126	      ...(active ? [key] : []),
127	    ]);
128	  };
