130	  return (
131	    <Tr key={rowIndex}>
132	      <Td
133	        dataLabel={columnNames[0]}
134	        favorites={{
135	          isFavorited: favorites.includes(userName),
136	          onFavorite: (_event, isFavoriting) =>
137	            onSetFavorite(userName, isFavoriting),
138	          rowIndex,
139	        }}
140	      />
141	      <Td dataLabel={columnNames[1]}>
142	        <Link to={path}>{userName}</Link>
143	      </Td>
144	      <Td dataLabel={columnNames[2]}>{creationDate}</Td>
145	      <Td dataLabel={columnNames[3]}>{passwordLastUsed}</Td>
146	      <Td dataLabel={columnNames[4]} isActionCell>
147	        <ActionsColumn
148	          items={getUsersActionsItems(
149	            t,
150	            launcher,
151	            userName,
152	            iamClient,
153	            triggerRefresh
154	          )}
155	        />
156	      </Td>
157	    </Tr>
158	  );
159	};
